ValidationRule.errorConditionFormula:
OR(
 AND(
 NATT_Number_of_eSolutions_Plan_1__c > 1,
   OR(
   NATT_Number_of_eSolutions_Plan_2__c != 0,
   NATT_Number_of_eSolutions_Plan_3__c != 0
   )
 ),
 AND(
 NATT_Number_of_eSolutions_Plan_2__c > 1,
   OR(
   NATT_Number_of_eSolutions_Plan_1__c != 0,
   NATT_Number_of_eSolutions_Plan_3__c != 0
   )
 ),
 AND(
 NATT_Number_of_eSolutions_Plan_3__c > 1,
   OR(
   NATT_Number_of_eSolutions_Plan_1__c != 0,
   NATT_Number_of_eSolutions_Plan_2__c != 0
   )
 )
)
